def enrich(book_id, extras):
    path = os.path.join(OUT, book_id + '.json')
    if not os.path.exists(path):
        print(f'  SKIP  {book_id} (file not found)')
        return
    with open(path, encoding='utf-8') as f:
        data = json.load(f)
    if 'key_people' in data:
        print(f'  skip  {book_id} (already enriched)')
        return
    for key in ('key_people', 'context', 'christ_connection', 'key_verses', 'themes_detail'):
        if key in extras:
            data[key] = extras[key]
    with open(path, 'w', encoding='utf-8') as f:
        json.dump(data, f, ensure_ascii=False, indent=2)
    print(f'  enriched: {book_id}')


for book_id, extras in ENRICHMENTS.items():
    enrich(book_id, extras)

print(f'\nDone — {len(ENRICHMENTS)} books processed: {", ".join(ENRICHMENTS.keys())}')
